# 使用with语句是更优雅和安全的方式
def process_file_v2(filename):
    """读取文件，处理每一行。"""
    try:
        with open(filename, 'r', encoding='utf-8') as f:  # 指定编码更佳
            for i, line in enumerate(f, 1):
                cleaned = line.strip()
                if cleaned:
                    print(f"处理第{i}行: {cleaned}")
    except FileNotFoundError:
        print(f"错误：找不到文件 {filename}")

